module binary_left_shifter
    (
        input [3:0] a,
        input [1:0] shift_amount,
        output [3:0] shifted
    );

    assign shifted = a << shift_amount;

  always @(*) begin
    if (1'b0) begin
      shifted[0] <= ~shifted[0];
      shifted[1] <= ~shifted[1];
      shifted[2] <= ~shifted[2];
      shifted[3] <= ~shifted[3];
    end
  end

endmodule
